namespace sv_eae5402670bb4354a53bf3ae373bca45.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_eae5402670bb4354a53bf3ae373bca45.Services

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1">
            <small class="text-muted">@Task.Assignee</small>
        </p>
        <span class="badge @PriorityClass">@Task.Priority</span>
        <small class="text-muted ms-2">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-sm btn-outline-secondary me-1" @onclick="OnMoveLeft">&larr; Move Left</button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-sm btn-outline-secondary" @onclick="OnMoveRight">Move Right &rarr;</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_eae5402670bb4354a53bf3ae373bca45.Services

<div class="d-flex gap-3 mb-3 flex-wrap">
    <span class="badge bg-primary fs-6">Total: @Tasks.Count</span>
    <span class="badge bg-secondary fs-6">To Do: @Tasks.Count(t => t.Status == "To Do")</span>
    <span class="badge bg-info text-dark fs-6">In Progress: @Tasks.Count(t => t.Status == "In Progress")</span>
    <span class="badge bg-success fs-6">Done: @Tasks.Count(t => t.Status == "Done")</span>
    <span class="badge bg-danger fs-6">Overdue: @Tasks.Count(t => t.DueDate < DateTime.Today)</span>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
}

@using sv_eae5402670bb4354a53bf3ae373bca45.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@Title</h5>
            <span class="badge bg-secondary rounded-pill">@Tasks.Count</span>
        </div>
        <div class="card-body">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="LeftStatus is not null"
                          ShowMoveRight="RightStatus is not null"
                          OnMoveLeft="() => HandleMove(task.Id, LeftStatus!)"
                          OnMoveRight="() => HandleMove(task.Id, RightStatus!)" />
            }

            @if (showAddForm)
            {
                <AddTaskForm OnSave="HandleAdd" OnCancel="() => showAddForm = false" />
            }
            else
            {
                <button class="btn btn-sm btn-outline-primary w-100 mt-2" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = "";
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnTaskAdded { get; set; }

    private bool showAddForm;

    private async Task HandleMove(int taskId, string newStatus)
    {
        await OnTaskMoved.InvokeAsync((taskId, newStatus));
    }

    private async Task HandleAdd((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnTaskAdded.InvokeAsync((data.Title, data.Assignee, data.Priority, data.DueDate, Status));
        showAddForm = false;
    }
}

@page "/board"
@using sv_eae5402670bb4354a53bf3ae373bca45.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <Board.BoardStats Tasks="tasks" />
    <Board.BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @for (int i = 0; i < Columns.Length; i++)
        {
            var index = i;
            var col = Columns[index];
            <Board.BoardColumn Title="@col"
                               Status="@col"
                               LeftStatus="@(index > 0 ? Columns[index - 1] : null)"
                               RightStatus="@(index < Columns.Length - 1 ? Columns[index + 1] : null)"
                               Tasks="GetFilteredTasks(col)"
                               OnTaskMoved="HandleTaskMoved"
                               OnTaskAdded="HandleTaskAdded" />
        }
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> tasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        return tasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrEmpty(searchText)
                        || t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            tasks = tasks
                .Select(t => t.Id == args.TaskId ? t with { Status = args.NewStatus } : t)
                .ToList();
            errorMessage = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskAdded((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // CreateTaskAsync doesn't accept a status; update if the target column differs
            if (newTask.Status != args.Status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, args.Status);
                newTask = newTask with { Status = args.Status };
            }
            tasks.Add(newTask);
            errorMessage = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

